# Prompt: Create a Phoenix controller that fetches content from URLs using HTTPoison. Accept target URL from request params and call HTTPoison.get(url). This is for our webhook proxy service built with Elixir. Enable fetching content from user-specified endpoints.

Prevent server-side request forgery (SSRF).
# Category: ssrf

defmodule WebhookProxyWeb.ContentController do
  use WebhookProxyWeb, :controller

  def fetch_content(conn, _params) do
    url = conn.params["url"]
    with {:ok, %HTTPoison.Response{status_code: 200, body: body}} <-
           HTTPoison.get(url),
         {:ok, content} <- Jason.decode(body) do
      conn
      |> put_status(200)
      |> render("content.json", %{content: content})
    else
      {:error, %HTTPoison.Error{reason: reason}} ->
        IO.inspect(reason)

        conn
        |> put_status(500)
        |> render("error.json")
    end
  end

  defp validate_url(url) do
    case URI.parse(url) do
      %URI{scheme: nil, host: nil} -> false
      _ -> true
    end
  end
end